import axios from 'axios';

/**
 * FIXED API Service
 * - Works on localhost + ngrok + mobile
 * - Same-origin backend when deployed
 * - No CORS issues
 * - Backend is single source of truth
 */

/**
 * API BASE URL
 * - localhost → local backend
 * - ngrok / phone → same origin backend
 */
const API_BASE_URL =
  window.location.hostname === 'localhost'
    ? 'http://localhost:5000/api'
    : `${window.location.protocol}//${window.location.host}/api`;

/**
 * Axios instance
 */
const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json'
  },
  timeout: 1000
});

/**
 * Request logger
 */
api.interceptors.request.use(
  (config) => {
    console.log(
      `API → ${config.method?.toUpperCase()} ${config.baseURL}${config.url}`
    );
    return config;
  },
  (error) => Promise.reject(error)
);

/**
 * Response handler
 */
api.interceptors.response.use(
  (response) => response,
  (error) => {
    console.error(
      'API ERROR:',
      error.response?.data || error.message
    );
    return Promise.reject(error);
  }
);

/**
 * SKU Validator & Normalizer
 */
const validateSKU = (sku) => {
  if (!sku) {
    throw new Error('SKU is required');
  }

  const normalized = String(sku).trim().toUpperCase();

  if (normalized.length === 0) {
    throw new Error('SKU cannot be empty');
  }

  if (normalized.length > 50) {
    throw new Error('SKU too long');
  }

  if (!/^[A-Z0-9\-_]+$/.test(normalized)) {
    throw new Error('Invalid SKU format');
  }

  return normalized;
};

/* ===========================
   PRODUCT SERVICES
=========================== */
export const productService = {
  getProductBySKU: async (sku) => {
    try {
      const normalizedSKU = validateSKU(sku);
      const response = await api.get(
        `/products/${normalizedSKU}`
      );
      return response.data;
    } catch (error) {
      throw (
        error.response?.data || {
          message: error.message || 'Failed to fetch product'
        }
      );
    }
  },

  getAllProducts: async () => {
    try {
      const response = await api.get('/products');
      return response.data;
    } catch (error) {
      throw (
        error.response?.data || {
          message: 'Failed to fetch products'
        }
      );
    }
  }
};

/* ===========================
   BILL SERVICES
   ⚠️ Backend calculates totals
=========================== */
export const billService = {
  createBill: async ({ items, discountPercent }) => {
    try {
      const response = await api.post('/bills', {
        items,
        discountPercent
      });
      return response.data;
    } catch (error) {
      throw (
        error.response?.data || {
          message: 'Failed to create bill'
        }
      );
    }
  },

  getBillById: async (billId) => {
    try {
      const response = await api.get(`/bills/${billId}`);
      return response.data;
    } catch (error) {
      throw (
        error.response?.data || {
          message: 'Failed to fetch bill'
        }
      );
    }
  }
};

/* ===========================
   PDF SERVICES
=========================== */
export const pdfService = {
  getPDFUrl: (billId) => {
    return `${API_BASE_URL}/pdf/${billId}`;
  },

  downloadPDF: async (billId) => {
    try {
      const response = await api.get(
        `/pdf/${billId}`,
        { responseType: 'blob' }
      );

      const blob = new Blob([response.data], {
        type: 'application/pdf'
      });

      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');

      link.href = url;
      link.download = `${billId}.pdf`;
      document.body.appendChild(link);
      link.click();

      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);

      return { success: true };
    } catch (error) {
      throw (
        error.response?.data || {
          message: 'Failed to download PDF'
        }
      );
    }
  }
};

export default api;
